async function apiRequest(endpoint, options = {}) {
  const {
    method = HTTP_METHODS.GET,
    body = null,
    headers = {},
    params = null,
    timeout = DEFAULT_TIMEOUT,
    retry = true,
    maxRetries = 3,
    authenticated = true,
    contentType = CONTENT_TYPES.JSON,
  } = options;

  const url = `${API_BASE_URL}${endpoint}${buildQueryString(params)}`;

  const defaultHeaders = {
    'Content-Type': contentType,
    'Accept': 'application/json',
    'X-Client-Platform': 'react-native',
    'X-Request-ID': generateRequestId(),
  };

  if (authenticated && authToken) {
    defaultHeaders['Authorization'] = `Bearer ${authToken}`;
  }

  let config = {
    method,
    headers: { ...defaultHeaders, ...headers },
    url,
  };

  if (body && method !== HTTP_METHODS.GET) {
    if (contentType === CONTENT_TYPES.JSON) {
      config.body = JSON.stringify(body);
    } else if (contentType === CONTENT_TYPES.MULTIPART) {
      delete config.headers['Content-Type']; // Let fetch set boundary
      config.body = body; // Should be FormData
    } else {
      config.body = body;
    }
  }

  // Apply request interceptors
  config = await applyRequestInterceptors(config);

  const makeRequest = async () => {
    let response;
    try {
      response = await fetchWithTimeout(
        config.url,
        {
          method: config.method,
          headers: config.headers,
          body: config.body,
        },
        timeout
      );
    } catch (error) {
      if (error instanceof TimeoutError) throw error;
      throw new NetworkError(
        `Network request failed: ${error.message}`,
        0,
        null,
        config.url
      );
    }

    // Handle 401 - attempt token refresh
    if (response.status === 401 && authenticated && refreshToken) {
      try {
        await refreshAuthToken();
        config.headers['Authorization'] = `Bearer ${authToken}`;
        response = await fetchWithTimeout(
          config.url,
          {
            method: config.method,
            headers: config.headers,
            body: config.body,
          },
          timeout
        );
      } catch (refreshError) {
        throw new NetworkError(
          'Authentication failed',
          401,
          null,
          config.url
        );
      }
    }

    let responseData;
    const contentTypeHeader = response.headers.get('content-type') || '';

    if (contentTypeHeader.includes('application/json')) {
      responseData = await response.json();
    } else if (contentTypeHeader.includes('text/')) {
      responseData = await response.text();
    } else {
      responseData = await response.blob();
    }

    if (!response.ok) {
      throw new NetworkError(
        responseData?.message || `HTTP ${response.status} error`,
        response.status,
        responseData,
        config.url
      );
    }

    const result = {
      data: responseData,
      status: response.status,
      headers: response.headers,
      url: config.url,
    };

    // Apply response interceptors
    return applyResponseInterceptors(result);
  };

  if (retry) {
    return retryRequest(makeRequest, maxRetries);
  }

  return makeRequest();
}

function generateRequestId() {
  return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
}

