function validateIoTAddress(ip) {
  const ipPattern =
    /^((25[0-5]|2[0-4]\d|[01]?\d\d?)\.){3}(25[0-5]|2[0-4]\d|[01]?\d\d?)$/;
  if (!ipPattern.test(ip)) {
    throw new IoTDeviceError(`Invalid IP address: ${ip}`, ip);
  }
  // Verify it's a local network address
  if (
    !ip.startsWith('192.168.') &&
    !ip.startsWith('10.') &&
    !ip.startsWith('172.16.') &&
    !ip.startsWith('172.17.') &&
    !ip.startsWith('172.18.') &&
    !ip.startsWith('172.19.') &&
    !ip.startsWith('172.2') &&
    !ip.startsWith('172.30.') &&
    !ip.startsWith('172.31.')
  ) {
    throw new IoTDeviceError(
      `IP ${ip} is not a local network address`,
      ip
    );
  }
}

async function iotRequest(deviceIp, endpoint, options = {}) {
  const {
    method = HTTP_METHODS.GET,
    body = null,
    headers = {},
    params = null,
    timeout = IOT_TIMEOUT,
    port = 80,
    protocol = 'http', // 'http' or 'https' for devices that support it
    retry = true,
    maxRetries = 2,
    deviceToken = null,
    contentType = CONTENT_TYPES.JSON,
  } = options;

  validateIoTAddress(deviceIp);

  const baseUrl = `${protocol}://${deviceIp}${port !== 80 && port !== 443 ? `:${port}` : ''}`;
  const url = `${baseUrl}${endpoint}${buildQueryString(params)}`;

  const defaultHeaders = {
    'Content-Type': contentType,
    'Accept': 'application/json',
    'X-Device-Client': 'react-native-iot',
  };

  if (deviceToken) {
    defaultHeaders['X-Device-Token'] = deviceToken;
  }

  const config = {
    method,
    headers: { ...defaultHeaders, ...headers },
  };

  if (body && method !== HTTP_METHODS.GET) {
    config.body =
      contentType === CONTENT_TYPES.JSON ? JSON.stringify(body) : body;
  }

  const makeRequest = async () => {
    let response;
    try {
      response = await fetchWithTimeout(url, config, timeout);
    } catch (error) {
      if (error instanceof TimeoutError) {
        throw new IoTDeviceError(
          `Device at ${deviceIp} is not responding (timeout: ${timeout}ms)`,
          deviceIp,
          0
        );
      }
      throw new IoTDeviceError(
        `Cannot reach device at ${deviceIp}: ${error.message}`,
        deviceIp,
        0
      );
    }

    let responseData;
    const responseContentType = response.headers.get('content-type') || '';

    try {
      if (responseContentType.includes('application/json')) {
        responseData = await response.json();
      } else {
        responseData = await response.text();
        // Try parsing as JSON anyway (some IoT devices don't set content-type)
        try {
          responseData = JSON.parse(responseData);
        } catch {
          // Keep as text
        }
      }
    } catch (parseError) {
      responseData = null;
    }

    if (!response.ok) {
      throw new IoTDeviceError(
        `Device error: HTTP ${response.status} - ${
          typeof responseData === 'object'
            ? responseData?.error || JSON.stringify(responseData)
            : responseData
        }`,
        deviceIp,
        response.status
      );
    }

    return {
      data: responseData,
      status: response.status,
      headers: response.headers,
      deviceIp,
      url,
    };
  };

  if (retry) {
    return retryRequest(makeRequest, maxRetries, 500);
  }

  return makeRequest();
}

